@file:OptIn(ExperimentalContracts::class)

package org.jetbrains.kotlin.java.direct

import kotlin.contracts.ExperimentalContracts
import kotlin.contracts.InvocationKind
import kotlin.contracts.contract

/**
 * Unified helpers for the `@Volatile`-backed lazy-cache pattern used throughout the java-direct
 * model layer. All helpers are `inline`, so the generated bytecode is identical to a hand-rolled
 * read-check-compute-store sequence with zero runtime overhead.
 *
 * ### Why not `by lazy(PUBLICATION)`?
 *
 * `by lazy(PUBLICATION)` allocates a `SafePublicationLazyImpl` wrapper (~24 B) plus a captured
 * lambda (~8 B) per delegate per instance. At ~200 K type-reference instances per compilation,
 * that adds up to tens of megabytes. These helpers provide the same semantics (idempotent compute
 * on race, safe publication via `@Volatile`) without the wrapper allocation.
 *
 * Kotlin 2.4's explicit backing fields cannot be used either: the feature disallows custom
 * accessors and requires the backing-field type to be a subtype of the property type.
 *
 * ### Concurrency model
 *
 * `@Volatile` fields ensure release/acquire semantics. A race yields the same value
 * (compute must be pure); the "last writer wins" outcome matches `by lazy(PUBLICATION)`.
 */

// --- Non-null cache ------------------------------------------------------------------------

/**
 * Lazy cache for a non-null property. The backing `@Volatile` field is declared as `T?` and
 * initialized to `null`, which encodes "not yet computed".
 *
 * Usage:
 * ```
 * @Volatile private var _typeParameters: List<JavaTypeParameter>? = null
 * override val typeParameters: List<JavaTypeParameter>
 *     get() = cachedNonNull({ _typeParameters }, { _typeParameters = it }) {
 *         computeTypeParameters(node, tree, resolutionContext)
 *     }
 * ```
 *
 * @param read snapshots the backing field. Must not have side effects.
 * @param write stores the computed value into the backing field.
 * @param compute the (possibly expensive) producer. Called at most once per instance under
 *                non-racy conditions; may be called more than once under racy reads, in which
 *                case the last writer wins — so [compute] must be a pure function.
 */
internal inline fun <T : Any> cachedNonNull(
    read: () -> T?,
    write: (T) -> Unit,
    compute: () -> T,
): T {
    contract {
        callsInPlace(read, InvocationKind.EXACTLY_ONCE)
        callsInPlace(write, InvocationKind.AT_MOST_ONCE)
        callsInPlace(compute, InvocationKind.AT_MOST_ONCE)
    }
    read()?.let { return it }
    val c = compute()
    write(c)
    return c
}

// --- Nullable cache with sentinel ----------------------------------------------------------

/**
 * Sentinel for [cachedNullable]: distinguishes "not yet computed" from "computed and the result
 * was null". Intentionally module-private so that every cache site shares the same instance;
 * having several per-class sentinels just wasted heap and obscured the pattern.
 */
internal val NOT_COMPUTED: Any = Any()

/**
 * Lazy cache for a nullable property, where `null` is a valid result that must be distinguished
 * from "not yet computed". The backing `@Volatile` field is declared as `Any?` and initialized
 * to [NOT_COMPUTED].
 *
 * Usage:
 * ```
 * @Volatile private var _fqName: Any? = NOT_COMPUTED
 * override val fqName: FqName?
 *     get() = cachedNullable({ _fqName }, { _fqName = it }) { computeFqName() }
 * ```
 *
 * The sentinel value is compared by reference; no equals/hashCode contract is required.
 */
internal inline fun <T> cachedNullable(
    read: () -> Any?,
    write: (Any?) -> Unit,
    compute: () -> T,
): T {
    contract {
        callsInPlace(read, InvocationKind.EXACTLY_ONCE)
        callsInPlace(write, InvocationKind.AT_MOST_ONCE)
        callsInPlace(compute, InvocationKind.AT_MOST_ONCE)
    }
    val cached = read()
    if (cached !== NOT_COMPUTED) {
        @Suppress("UNCHECKED_CAST")
        return cached as T
    }
    val c = compute()
    write(c)
    return c
}

// --- Boolean cache (tri-state Int) ---------------------------------------------------------

/**
 * Lazy cache for a `Boolean` property. Encodes the tri-state
 * `-1 = not computed, 0 = false, 1 = true` in a single `Int` field so that the backing slot is
 * four bytes instead of the ≥ 8 bytes a boxed `Boolean?` would take.
 *
 * The backing `@Volatile Int` field must be initialized to `-1`.
 *
 * Usage:
 * ```
 * @Volatile private var _isInterface: Int = -1
 * override val isInterface: Boolean
 *     get() = cachedBoolean({ _isInterface }, { _isInterface = it }) {
 *         tree.findChildByType(node, JavaSyntaxTokenType.INTERFACE_KEYWORD) != null
 *     }
 * ```
 */
internal inline fun cachedBoolean(
    read: () -> Int,
    write: (Int) -> Unit,
    compute: () -> Boolean,
): Boolean {
    contract {
        callsInPlace(read, InvocationKind.EXACTLY_ONCE)
        callsInPlace(write, InvocationKind.AT_MOST_ONCE)
        callsInPlace(compute, InvocationKind.AT_MOST_ONCE)
    }
    val cached = read()
    if (cached >= 0) return cached != 0
    val c = compute()
    write(if (c) 1 else 0)
    return c
}
